            Tags = """["invoices","accounting","walkthrough"]""",
            ContentJson = """{"appRoute":"/invoices","startButtonLabel":"Tour Invoices","steps":[{"element":"[data-testid='new-invoice-btn']","popover":{"title":"Create an Invoice","description":"Click here to start a new invoice. A window opens where you add line items on one side and fill in details like the customer, dates, and tax rate on the other. Add at least one line item before you save.","side":"bottom"}},{"element":".page-header .action-btn:first-of-type","popover":{"title":"Uninvoiced Jobs","description":"Opens a panel of finished jobs that haven't been billed yet. Each one has an 'Invoice' button that builds the invoice for you. The number on the button tells you how many are waiting.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search Invoices","description":"Type an invoice number or customer name to find an invoice. The list narrows as you type. Press Enter to apply it too.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Filter by Status","description":"Show only invoices in one status, such as Draft, Sent, Partially Paid, Paid, Overdue, or Voided. Pick 'All Statuses' to see everything again.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"The Invoice List","description":"Every invoice shows here with its number, customer, status, dates, total, amount paid, and balance due. Click a row to open it. Click a column heading to sort. Overdue balances appear in red.","side":"top"}}]}"""
