            ContentJson = """{"title":"Invoices Field Reference","groups":[{"heading":"Invoice Details (Create Window)","items":[{"label":"Customer (required)","value":"Pick who the invoice is billed to from your active customers. You must choose one before you can save."},{"label":"Sales Order ID","value":"Optional. Ties the invoice to an existing sales order so you can trace the order through to payment. It shows as a clickable link on the invoice."},{"label":"Invoice Date (required)","value":"The date you're issuing the invoice. Shown as MM/dd/yyyy."},{"label":"Due Date (required)","value":"The date payment is expected. If this date passes unpaid, the invoice becomes Overdue. Shown as MM/dd/yyyy."},{"label":"Credit Terms","value":"Optional. Pick a standard payment term, such as Net 30 or Due on Receipt, to tell the customer when payment is due."},{"label":"Tax Rate (required)","value":"The tax percentage applied to the subtotal. Starts at 0 and can't be negative. The tax and total update as you change it."},{"label":"Shipment ID","value":"Optional. Ties the invoice to a specific shipment, handy when you bill one delivery at a time."},{"label":"Notes","value":"Optional. Any notes you want to appear on the invoice."}]},{"heading":"Line Items (Create Window)","items":[{"label":"Part ID","value":"Optional. Links the line to a part record so you can trace it."},{"label":"Part Number","value":"Optional. The part number that prints on the invoice."},{"label":"Description (required)","value":"What you're billing for. Can't be left blank."},{"label":"Qty (required)","value":"How many. Starts at 1 and must be more than 0. Partial amounts like 0.5 are allowed."},{"label":"Unit Price (required)","value":"Price for one. Can't be negative. Shown as money."},{"label":"Total (automatic)","value":"Qty times Unit Price, worked out for you. Shown as money. You can't edit it."},{"label":"Add button","value":"Adds the line to the invoice. Stays off until the description, quantity, and price are all valid."},{"label":"Remove button (X)","value":"The red X on each line removes that line from the invoice."}]},{"heading":"Invoice Summary (Create Window)","items":[{"label":"Subtotal","value":"All the line totals added up. Updates as you add or remove lines."},{"label":"Tax","value":"The subtotal times your tax rate. The rate is shown in parentheses."},{"label":"Total","value":"Subtotal plus tax. This is the full amount the customer owes."}]},{"heading":"Invoice Statuses","items":[{"label":"Draft (gray)","value":"Created but not sent yet. You can send, void, or delete it. To change a Draft, delete it and make a new one."},{"label":"Sent (blue)","value":"Sent to the customer and waiting on payment. You can void it but no longer delete it."},{"label":"Partially Paid (yellow)","value":"The customer has paid part of it. The balance due shows what's left. It can't be voided or deleted."},{"label":"Paid (green)","value":"Paid in full. The balance due is $0.00 and there's nothing left to do."},{"label":"Overdue (red)","value":"The due date has passed and money is still owed. The balance due shows in red on the list."},{"label":"Voided (gray)","value":"Cancelled. It stays on file for your records but doesn't affect any totals. You can't undo a void."}]},{"heading":"On an Open Invoice","items":[{"label":"Invoice Number","value":"The invoice's ID, shown at the top."},{"label":"Customer","value":"A clickable link that opens the customer's page."},{"label":"Sales Order","value":"A clickable link to the linked sales order. Only appears when one is linked."},{"label":"Shipment","value":"A clickable link to the linked shipment. Only appears when one is linked."},{"label":"Invoice Date","value":"The date the invoice was issued, shown as MM/dd/yyyy."},{"label":"Due Date","value":"The date payment is due, shown as MM/dd/yyyy."},{"label":"Credit Terms","value":"The payment term, such as Net 30. Only appears when one is set."},{"label":"Notes","value":"Any notes on the invoice. Only appears when there are some."},{"label":"Line Items","value":"Each billed line with its part number, description, quantity, unit price, and total. A dash shows where there's no part number."},{"label":"Subtotal","value":"All the line totals added up."},{"label":"Tax (rate%)","value":"The tax amount, with the rate shown in parentheses."},{"label":"Total","value":"The full amount owed: subtotal plus tax."},{"label":"Amount Paid","value":"How much has been paid toward this invoice so far."},{"label":"Balance Due","value":"What's still owed: the total minus what's been paid. It stands out when there's a balance."},{"label":"Created / Updated","value":"When the invoice was made and last changed, shown as MM/dd/yyyy."},{"label":"Activity Log","value":"A running history of everything that happened to the invoice, newest changes and all."}]},{"heading":"Buttons and Actions","items":[{"label":"New Invoice","value":"Opens the window to build a new invoice."},{"label":"Uninvoiced Jobs","value":"Opens a panel of finished jobs that still need billing. The number shows how many are waiting."},{"label":"Create Invoice (save)","value":"Saves the new invoice. Stays off until the invoice is complete, has at least one line, and isn't already saving. Hover it to see what's still needed."},{"label":"Cancel","value":"Closes the window without saving. Asks first if you have unsaved changes."},{"label":"Send","value":"Marks the invoice as Sent. Only there while it's still a Draft."},{"label":"Void","value":"Cancels the invoice after you confirm. Available while it's a Draft or Sent."},{"label":"Delete","value":"Removes the invoice after you confirm. Only there while it's still a Draft."},{"label":"Close","value":"Closes the open invoice."},{"label":"Invoice from Job","value":"Builds an invoice straight from a finished job, filling in the customer and line items. Off if the job has no customer assigned."},{"label":"Click a row","value":"Opens that invoice. The web address updates so you can bookmark it or share the link."}]},{"heading":"What's Required to Save","items":[{"label":"Customer","value":"Required. Pick a customer."},{"label":"Invoice Date","value":"Required. Choose a date."},{"label":"Due Date","value":"Required. Choose a date."},{"label":"Tax Rate","value":"Required. A number that isn't negative."},{"label":"At least one line item","value":"You can't save until you've added at least one line."},{"label":"Line Description","value":"Required on every line. Can't be blank."},{"label":"Line Quantity","value":"Required. More than 0. Partial amounts are allowed."},{"label":"Line Unit Price","value":"Required. Can't be negative."},{"label":"What's-missing hint","value":"Hover the greyed-out Save button to see a list of what still needs filling in."}]},{"heading":"List Columns","items":[{"label":"Invoice #","value":"Sortable. The invoice number."},{"label":"Customer","value":"Sortable. The customer's name."},{"label":"Status","value":"Sortable and filterable. A colored label: Draft (gray), Sent (blue), Partially Paid (yellow), Paid (green), Overdue (red), Voided (gray)."},{"label":"Invoice Date","value":"Sortable. The date issued, shown as MM/dd/yyyy."},{"label":"Due Date","value":"Sortable. The date payment is due, shown as MM/dd/yyyy."},{"label":"Total","value":"Sortable. The invoice total, shown as money."},{"label":"Paid","value":"Sortable. How much has been paid so far, shown as money."},{"label":"Balance","value":"Sortable. What's still owed. Yellow when there's a balance, red when it's overdue."},{"label":"Created","value":"Sortable. The date the invoice was made, shown as MM/dd/yyyy."}]}]}"""
